import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './WelcomeScreen.css';

const WelcomeScreen = ({ config }) => {
  const navigate = useNavigate();
  const [recentMeetings, setRecentMeetings] = useState([]);
  const [stats, setStats] = useState(null);
  const [showAdminLogin, setShowAdminLogin] = useState(false);
  const [adminPassword, setAdminPassword] = useState('');
  const [isAdminAuthenticated, setIsAdminAuthenticated] = useState(false);

  useEffect(() => {
    // Check if admin is already authenticated
    const adminToken = localStorage.getItem('clientAdminToken');
    if (adminToken) {
      setIsAdminAuthenticated(true);
      axios.defaults.headers.common['Authorization'] = `Bearer ${adminToken}`;
    }

    // Fetch recent meetings and stats
    const fetchData = async () => {
      try {
        const [meetingsRes, statsRes] = await Promise.all([
          axios.get('/meetings?limit=3').catch(() => ({ data: { meetings: [] } })),
          axios.get('/admin/stats').catch(() => ({ data: {} }))
        ]);
        setRecentMeetings(meetingsRes.data.meetings || []);
        setStats(statsRes.data || {});
      } catch (error) {
        console.error('Error fetching data:', error);
      }
    };
    fetchData();
  }, []);

  const handleAdminLogin = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.post('/admin/login', {
        username: 'admin',
        password: adminPassword
      });

      if (response.data.token) {
        localStorage.setItem('clientAdminToken', response.data.token);
        axios.defaults.headers.common['Authorization'] = `Bearer ${response.data.token}`;
        setIsAdminAuthenticated(true);
        setShowAdminLogin(false);
        setAdminPassword('');
        navigate('/admin');
      }
    } catch (error) {
      alert('Invalid password. Please try again.');
      setAdminPassword('');
    }
  };

  const handleAdminLogout = () => {
    localStorage.removeItem('clientAdminToken');
    delete axios.defaults.headers.common['Authorization'];
    setIsAdminAuthenticated(false);
  };

  return (
    <div className="welcome-screen">
      {/* Top Header with Admin Access */}
      <div className="welcome-top-header">
        <div className="header-spacer"></div>
        <button 
          className="header-admin-btn"
          onClick={() => {
            if (isAdminAuthenticated) {
              navigate('/admin');
            } else {
              setShowAdminLogin(true);
            }
          }}
        >
          <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
            <circle cx="12" cy="12" r="3"></circle>
            <path d="M12 1v6m0 6v6M5.64 5.64l4.24 4.24m4.24 4.24l4.24 4.24M1 12h6m6 0h6M5.64 18.36l4.24-4.24m4.24-4.24l4.24-4.24"></path>
          </svg>
          <span>Admin</span>
        </button>
      </div>

      <div className="welcome-container">
        <div className="welcome-header">
          <div className="logo-container">
            <img 
              src="/assets/portiq-logo.png" 
              alt="PortIQ Technologies" 
              className="portiq-logo"
              onError={(e) => {
                e.target.style.display = 'none';
              }}
            />
          </div>
          <h1 className="welcome-title">AI-Powered Meeting Assistant</h1>
          <p className="welcome-subtitle">AI-Powered Meeting Intelligence Platform</p>
        </div>

        <div className="home-stats">
          {stats && (
            <div className="stats-grid">
              <div className="stat-card">
                <div className="stat-icon">
                  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <rect x="3" y="4" width="18" height="18" rx="2" ry="2"></rect>
                    <line x1="16" y1="2" x2="16" y2="6"></line>
                    <line x1="8" y1="2" x2="8" y2="6"></line>
                    <line x1="3" y1="10" x2="21" y2="10"></line>
                  </svg>
                </div>
                <div className="stat-value">{stats.totalMeetings || 0}</div>
                <div className="stat-label">Total Meetings</div>
              </div>
              <div className="stat-card">
                <div className="stat-icon">
                  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <polyline points="20 6 9 17 4 12"></polyline>
                  </svg>
                </div>
                <div className="stat-value">{stats.completedMeetings || 0}</div>
                <div className="stat-label">Completed</div>
              </div>
              <div className="stat-card">
                <div className="stat-icon">
                  <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <circle cx="12" cy="12" r="10"></circle>
                    <polyline points="12 6 12 12 16 14"></polyline>
                  </svg>
                </div>
                <div className="stat-value">{stats.todayMeetings || 0}</div>
                <div className="stat-label">Today</div>
              </div>
            </div>
          )}
        </div>

        <div className="welcome-actions">
          <button 
            className="action-btn primary"
            onClick={() => navigate('/meetings')}
          >
            <span className="btn-icon">
              <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M12 1a3 3 0 0 0-3 3v8a3 3 0 0 0 6 0V4a3 3 0 0 0-3-3z"></path>
                <path d="M19 10v2a7 7 0 0 1-14 0v-2"></path>
                <line x1="12" y1="19" x2="12" y2="23"></line>
                <line x1="8" y1="23" x2="16" y2="23"></line>
              </svg>
            </span>
            <span className="btn-text">Start New Meeting</span>
          </button>

          {recentMeetings.length > 0 && (
            <button 
              className="action-btn secondary"
              onClick={() => navigate('/meetings')}
            >
              <span className="btn-icon">
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"></path>
                  <polyline points="14 2 14 8 20 8"></polyline>
                  <line x1="16" y1="13" x2="8" y2="13"></line>
                  <line x1="16" y1="17" x2="8" y2="17"></line>
                  <polyline points="10 9 9 9 8 9"></polyline>
                </svg>
              </span>
              <span className="btn-text">View Recent Meetings</span>
            </button>
          )}
        </div>

        {recentMeetings.length > 0 && (
          <div className="recent-meetings">
            <h3 className="recent-title">Recent Meetings</h3>
            <div className="meetings-list">
              {recentMeetings.slice(0, 3).map((meeting) => (
                <div 
                  key={meeting._id} 
                  className="meeting-card"
                  onClick={() => navigate('/meetings')}
                >
                  <div className="meeting-card-header">
                    <span className="meeting-title">{meeting.title}</span>
                    <span className={`meeting-status status-${meeting.status?.toLowerCase()}`}>
                      {meeting.status}
                    </span>
                  </div>
                  <div className="meeting-card-details">
                    <span className="meeting-room">
                      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" style={{ display: 'inline', marginRight: '6px', verticalAlign: 'middle' }}>
                        <path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z"></path>
                        <circle cx="12" cy="10" r="3"></circle>
                      </svg>
                      {meeting.meetingRoom}
                    </span>
                    <span className="meeting-date">
                      {new Date(meeting.startTime).toLocaleDateString()}
                    </span>
                  </div>
                  {meeting.summary && (
                    <div className="meeting-summary-badge">
                      <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" style={{ display: 'inline', marginRight: '4px', verticalAlign: 'middle' }}>
                        <polyline points="20 6 9 17 4 12"></polyline>
                      </svg>
                      Summary Available
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        )}
      </div>

      <div className="branding-footer">
        PortIQ Meeting Assistant
      </div>

      {/* Admin Access Button */}
      <button 
        className="admin-access-btn"
        onClick={() => {
          if (isAdminAuthenticated) {
            navigate('/admin');
          } else {
            setShowAdminLogin(true);
          }
        }}
        title={isAdminAuthenticated ? "Admin Panel" : "Admin Access"}
      >
        <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
          <rect x="3" y="11" width="18" height="11" rx="2" ry="2"></rect>
          <path d="M7 11V7a5 5 0 0 1 10 0v4"></path>
        </svg>
      </button>

      {/* Admin Login Modal */}
      {showAdminLogin && (
        <div className="admin-login-modal-overlay" onClick={() => setShowAdminLogin(false)}>
          <div className="admin-login-modal" onClick={(e) => e.stopPropagation()}>
            <h2>Admin Access</h2>
            <p>Enter password to access meeting records</p>
            <form onSubmit={handleAdminLogin}>
              <input
                type="password"
                placeholder="Enter admin password"
                value={adminPassword}
                onChange={(e) => setAdminPassword(e.target.value)}
                autoFocus
                className="admin-password-input"
              />
              <div className="admin-login-actions">
                <button type="submit" className="admin-login-submit">Access</button>
                <button type="button" className="admin-login-cancel" onClick={() => {
                  setShowAdminLogin(false);
                  setAdminPassword('');
                }}>Cancel</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default WelcomeScreen;
